def decode_hieroglyphic_sum(hieroglyphs: str) -> int:
    symbol_values = {'I': 1, 'V': 5, 'X': 10}
    total = 0

    for i in range(len(hieroglyphs)):
        value = symbol_values.get(hieroglyphs[i], 0)
        if i > 0 and symbol_values.get(hieroglyphs[i - 1], 0) < value:
            total += value - symbol_values.get(hieroglyphs[i - 1], 0)
        else:
            total += value

    return total
